import type Color from "../../Color.js";

/**
 * Describes a theme that pairs well with the given basemaps.
 * See the table below for more details of the properties in this object.
 *
 * @since 5.0
 */
export interface Theme {
  /**
   * The Esri basemaps that pair well with the given theme.
   *
   * @since 5.0
   */
  basemaps: string[];
  /**
   * Text describing the theme in the UI.
   *
   * @since 5.0
   */
  description: string;
  /**
   * The label identifying the theme in UI elements.
   *
   * @since 5.0
   */
  label: string;
  /**
   * The name of the theme.
   *
   * @since 5.0
   */
  name: string;
}

/** @since 5.0 */
export interface SchemeOutline {
  /**
   * The outline color of the symbol.
   *
   * @since 5.0
   */
  color: Color;
  /**
   * The width of the symbol in pixels or points.
   *
   * @since 5.0
   */
  width: string | number;
}

/**
 * Properties defining the symbology scheme used to visualize point features with attribute data-driven color.
 *
 * @since 5.0
 */
export interface ColorSchemeForPoint {
  /**
   * The unique id of the color scheme to use in the visualization. The id is
   * assigned based on the following template: `<themeName>/<basemapName>/<schemeName>`.
   *
   * @since 5.0
   */
  id: string;
  /**
   * The unique name of the scheme.
   *
   * @since 5.0
   */
  name: string;
  /**
   * Tags associated with the scheme.
   *
   * @since 5.0
   */
  tags: string[];
  /**
   * Indicates which values will be emphasized in the continuous ramp and the map.
   * Possible values are listed below.
   * | Value | Description | Example |
   * | ----- | ----------- | ------- |
   * | high-to-low | High values are emphasized with strong colors. | ![high-to-low](https://developers.arcgis.com/javascript/latest/assets/references/core/renderers/sm-high-to-low.png) |
   * | above-and-below | Values centered around a given point (e.g. the average) are visualized with weak colors while other values are emphasized with strong colors. | ![above-and-below](https://developers.arcgis.com/javascript/latest/assets/references/core/renderers/sm-above-and-below.png) |
   * | centered-on | Values centered around a given point (e.g. the average) are emphasized with strong colors while other values are visualized with weak colors. | ![centered-on](https://developers.arcgis.com/javascript/latest/assets/references/core/renderers/sm-centered-on.png) |
   * | extremes | High and low values are emphasized with strong colors. All others are visualized with weak colors. | ![extremes](https://developers.arcgis.com/javascript/latest/assets/references/core/renderers/sm-extremes.png) |
   *
   * @since 5.0
   */
  theme: string;
  /**
   * The continuous color ramp that will be applied to the visualization.
   *
   * @since 5.0
   */
  colors: Color[];
  /**
   * Predefined classed color schemes to use for the visualization.
   *
   * @since 5.0
   */
  colorsForClassBreaks: ColorsForClassBreak[];
  /**
   * The color of the symbol used to indicate
   * features with no data and features that are out of range.
   *
   * @since 5.0
   */
  noDataColor: Color;
  /**
   * The opacity of the symbol.
   *
   * @since 5.0
   */
  opacity: number;
  /**
   * Properties for defining the outline of the symbol.
   *
   * @since 5.0
   */
  outline: SchemeOutline;
  /**
   * The default size of the symbol in pixels or points.
   *
   * @since 5.0
   */
  size: string | number;
}

