/**
 * Suggested property values for defining the scheme used to visualize flow lines.
 *
 * @since 5.0
 */
export interface FlowScheme {
  /**
   * The unique id of the color scheme to use in the visualization. The id is
   * assigned based on the following template: `<themeName>/<basemapName>/<schemeName>`.
   *
   * @since 5.0
   */
  id: string;
  /**
   * The unique name of the scheme.
   *
   * @since 5.0
   */
  name: string;
  /**
   * Tags associated with the scheme.
   *
   * @since 5.0
   */
  tags: string[];
  /**
   * Determines how flow lines will render.
   *   Possible values are listed below.
   * | Value | Description | Example |
   * | ----- | ----------- | ------- |
   * | flow-line | Renders the uv and magnitude data as animated flow lines. This is ideal for representing wind and other atmospheric data. | ![flow-line](https://developers.arcgis.com/javascript/latest/assets/references/core/renderers/animated-flow/sm-flow-line-2.gif) |
   * | wave-front | Renders UV and magnitude data in a wave-like animation. This theme works well for ocean data. | ![above](https://developers.arcgis.com/javascript/latest/assets/references/core/renderers/animated-flow/sm-wave-front-2.gif) |
   *
   * > [!WARNING]
   * >
   * > **Known Limitations**
   * >
   * > The `wave-front` flow theme is not supported in 3D [SceneView](https://developers.arcgis.com/javascript/latest/references/core/views/SceneView/).
   *
   * @since 5.0
   */
  theme: "flow-line" | "wave-front";
  /**
   * The suggested color of the flow lines if a color visual variable is not desired.
   *
   * @since 5.0
   */
  color: Color;
  /**
   * The suggested colors to use if a
   *   [ColorVariable](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/ColorVariable/) is set on the flow renderer.
   *
   * @since 5.0
   */
  colors: Color[];
  /**
   * The suggested [FlowRenderer.density](https://developers.arcgis.com/javascript/latest/references/core/renderers/FlowRenderer/#density) of the streamlines.
   *
   * @since 5.0
   */
  density: number;
  /**
   * The suggested [FlowRenderer.flowSpeed](https://developers.arcgis.com/javascript/latest/references/core/renderers/FlowRenderer/#flowSpeed) of the streamlines.
   *
   * @since 5.0
   */
  flowSpeed: number;
  /**
   * The suggested [length](https://developers.arcgis.com/javascript/latest/references/core/renderers/FlowRenderer/#trailLength) of the streamlines.
   *
   * @since 5.0
   */
  trailLength: number;
  /**
   * The suggested [width](https://developers.arcgis.com/javascript/latest/references/core/renderers/FlowRenderer/#trailWidth) of the streamlines.
   *
   * @since 5.0
   */
  trailWidth: number;
  /**
   * The suggested [cap style](https://developers.arcgis.com/javascript/latest/references/core/renderers/FlowRenderer/#trailCap) of the streamlines.
   *
   * > [!WARNING]
   * >
   * > **Known Limitations**
   * >
   * > The `round` trail cap is not supported in 3D [SceneView](https://developers.arcgis.com/javascript/latest/references/core/views/SceneView/).
   *
   * @since 5.0
   */
  trailCap: "butt" | "round";
  /**
   * The suggested [ImageryTileLayer.effect](https://developers.arcgis.com/javascript/latest/references/core/layers/ImageryTileLayer/#effect) to apply to the input layer.
   *
   * > [!WARNING]
   * >
   * > **Known Limitations**
   * >
   * > The layer effects are not supported in 3D [SceneView](https://developers.arcgis.com/javascript/latest/references/core/views/SceneView/).
   *
   * @since 5.0
   */
  layerEffect: string;
  /**
   * The suggested size to apply to small magnitude values if a
   *   [SizeVariable](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/SizeVariable/) is set on the flow renderer.
   *
   * @since 5.0
   */
  minSize: number;
  /**
   * The suggested size to apply to large magnitude values if a
   *   [SizeVariable](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/SizeVariable/) is set on the flow renderer.
   *
   * @since 5.0
   */
  maxSize: number;
  /**
   * The suggested opacity to apply to small magnitude values if an
   *   [OpacityVariable](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/OpacityVariable/) is set on the flow renderer.
   *
   * @since 5.0
   */
  minOpacity: number;
  /**
   * The suggested opacity to apply to large magnitude values if an
   *   [OpacityVariable](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/OpacityVariable/) is set on the flow renderer.
   *
   * @since 5.0
   */
  maxOpacity: number;
}

